/**
 * Repair Ticket — campaign repair queue model
 *
 * IRepairTicket entries are auto-generated by the repair queue builder
 * (post-battle) and consumed by the existing maintenance/repair UI.
 * Each ticket represents one atomic repair task: a single armor patch,
 * a single structure rebuild, a single component swap, or a single
 * ammo restock. Heat-recovery tickets are placeholders for cool-down
 * tracking (not real "work" but kept in the queue for visibility).
 *
 * @module types/campaign/RepairTicket
 */

/**
 * Kind of repair work the ticket represents.
 *
 * - `armor` — restore N armor points to a location
 * - `structure` — rebuild internal structure points (more expensive than armor)
 * - `component` — replace a destroyed weapon, heat sink, actuator, etc.
 * - `ammo` — restock ammo bin to construction max
 * - `heat-recovery` — passive cool-down tracking (no parts, no hours)
 */
export type RepairTicketKind =
  | 'armor'
  | 'structure'
  | 'component'
  | 'ammo'
  | 'heat-recovery';

/**
 * Lifecycle status of a repair ticket.
 *
 * - `queued` — waiting for tech availability
 * - `in-progress` — actively being worked on by a tech
 * - `parts-needed` — blocked on missing parts (acquisition or salvage)
 * - `completed` — work done, unit restored
 * - `cancelled` — user dismissed the ticket
 */
export type RepairTicketStatus =
  | 'queued'
  | 'in-progress'
  | 'parts-needed'
  | 'completed'
  | 'cancelled';

/**
 * Origin of a repair ticket.
 *
 * - `combat` — generated by the post-battle repair-queue processor
 * - `maintenance` — generated by routine maintenance failure
 * - `manual` — user-created via the repair UI
 */
export type RepairTicketSource = 'combat' | 'maintenance' | 'manual';

/**
 * One required part for a repair ticket.
 *
 * `matched` indicates whether the part has been located in the salvage
 * pool or general inventory. Unmatched requirements block the ticket.
 */
export interface IRepairPartRequirement {
  /** Identifier for the part (e.g., 'medium-laser', 'standard-armor-pt') */
  readonly partId: string;
  /** How many of this part the ticket consumes */
  readonly quantity: number;
  /** True once the part has been reserved from inventory or salvage */
  readonly matched: boolean;
  /** Optional source bin/lot the part was matched from */
  readonly matchedFromInventoryId?: string;
}

/**
 * Auto-generated repair work item attached to a campaign.
 *
 * Tickets are created by the `repairQueueBuilderProcessor` from combat
 * outcomes and persisted on `campaign.repairQueue`. The existing
 * maintenance day-processor ticks them down over time.
 *
 * Idempotency: tickets generated from the same `matchId` are de-duped
 * by the processor, so re-running the post-battle pipeline on the same
 * outcome will not create duplicate tickets.
 */
export interface IRepairTicket {
  /** Unique identifier for this ticket */
  readonly ticketId: string;

  /** Unit being repaired */
  readonly unitId: string;

  /** Kind of repair work this ticket represents */
  readonly kind: RepairTicketKind;

  /** Mech location (e.g., 'LT', 'CT', 'RA') — for armor/structure/component */
  readonly location?: string;

  /** Component name (e.g., 'AC/20', 'Medium Laser') — for component kind */
  readonly componentName?: string;

  /** Ammo bin identifier — for ammo kind */
  readonly ammoBinId?: string;

  /** Points to restore — for armor/structure kinds */
  readonly pointsToRestore?: number;

  /** Estimated tech-hours required to complete the work */
  readonly expectedHours: number;

  /** Parts required to complete the ticket */
  readonly partsRequired: ReadonlyArray<IRepairPartRequirement>;

  /** Origin of this ticket */
  readonly source: RepairTicketSource;

  /** Match/battle ID the ticket originated from; null for maintenance/manual */
  readonly matchId: string | null;

  /** Creation timestamp (ISO 8601) */
  readonly createdAt: string;

  /** Current lifecycle status */
  readonly status: RepairTicketStatus;
}
